import{_ as e,o as a,c as l,ag as o}from"./chunks/framework.ppPvAPr9.js";const k=JSON.parse('{"title":"Vue 面试题","description":"","frontmatter":{},"headers":[],"relativePath":"interview/Vue/vue.md","filePath":"interview/Vue/vue.md"}'),s={name:"interview/Vue/vue.md"};function t(d,i,h,r,n,c){return a(),l("div",null,[...i[0]||(i[0]=[o('<h1 id="vue-面试题" tabindex="-1">Vue 面试题 <a class="header-anchor" href="#vue-面试题" aria-label="Permalink to &quot;Vue 面试题&quot;">​</a></h1><h2 id="基础认知篇" tabindex="-1">基础认知篇 <a class="header-anchor" href="#基础认知篇" aria-label="Permalink to &quot;基础认知篇&quot;">​</a></h2><h2 id="q-vue-框架理解" tabindex="-1">Q: Vue 框架理解 <a class="header-anchor" href="#q-vue-框架理解" aria-label="Permalink to &quot;Q: Vue 框架理解&quot;">​</a></h2><p><strong>A:</strong></p><p>Vue 是一套用于构建用户界面的渐进式框架，核心思想是“数据驱动视图 + 组件化开发”。</p><ol><li>响应式：数据变化后，视图会自动更新。</li><li>组件化：将页面拆分为高复用、低耦合的组件。</li><li>渐进式：可从模板增强逐步过渡到工程化全家桶。</li><li>生态完善：路由、状态管理、构建工具与社区方案成熟。</li></ol><hr><h2 id="q-spa-单页应用优缺点和实现方式是什么" tabindex="-1">Q: SPA 单页应用优缺点和实现方式是什么？ <a class="header-anchor" href="#q-spa-单页应用优缺点和实现方式是什么" aria-label="Permalink to &quot;Q: SPA 单页应用优缺点和实现方式是什么？&quot;">​</a></h2><p><strong>A:</strong></p><p>SPA（Single Page Application）是单页面应用，首次加载后通过前端路由切换视图，通常不整页刷新。</p><p>优点：</p><ol><li>交互流畅，页面切换体验好。</li><li>前后端职责清晰，便于分工。</li><li>更适合组件化和状态管理。</li></ol><p>缺点：</p><ol><li>首屏资源可能较大，需要优化加载策略。</li><li>SEO 天然较弱，通常要配合 SSR/预渲染。</li><li>路由配置或服务端回退配置不当时容易出现刷新 404。</li></ol><p>实现关键：</p><ol><li>路由模式：<code>hash</code> 或 <code>history</code>。</li><li>路由监听：路径变化后渲染对应组件。</li><li>服务端配置：<code>history</code> 模式需将未知路径回退到 <code>index.html</code>。</li></ol><hr><h2 id="q-v-if-和-v-show-的区别是什么" tabindex="-1">Q: <code>v-if</code> 和 <code>v-show</code> 的区别是什么？ <a class="header-anchor" href="#q-v-if-和-v-show-的区别是什么" aria-label="Permalink to &quot;Q: `v-if` 和 `v-show` 的区别是什么？&quot;">​</a></h2><p><strong>A:</strong></p><p><code>v-if</code> 是“真正的条件渲染”，<code>v-show</code> 是“显示状态切换”。</p><ol><li><code>v-if</code>：条件不满足时不渲染节点，涉及创建/销毁。</li><li><code>v-show</code>：始终渲染节点，仅切换 <code>display: none</code>。</li><li>高频切换用 <code>v-show</code> 更合适；初次是否展示不确定且切换少，优先 <code>v-if</code>。</li></ol><hr><h2 id="q-v-if-和-v-for-为什么不建议写在同一个元素上" tabindex="-1">Q: <code>v-if</code> 和 <code>v-for</code> 为什么不建议写在同一个元素上？ <a class="header-anchor" href="#q-v-if-和-v-for-为什么不建议写在同一个元素上" aria-label="Permalink to &quot;Q: `v-if` 和 `v-for` 为什么不建议写在同一个元素上？&quot;">​</a></h2><p><strong>A:</strong></p><p>同时使用会增加模板理解和渲染成本，也容易产生优先级误解（不同版本行为有差异）。</p><p>推荐做法：</p><ol><li>先在计算属性中过滤列表，再 <code>v-for</code>。</li><li>或将 <code>v-if</code> 提升到外层容器。</li></ol><hr><h2 id="响应式与渲染篇" tabindex="-1">响应式与渲染篇 <a class="header-anchor" href="#响应式与渲染篇" aria-label="Permalink to &quot;响应式与渲染篇&quot;">​</a></h2><h2 id="q-vue2-响应式原理" tabindex="-1">Q: Vue2 响应式原理 <a class="header-anchor" href="#q-vue2-响应式原理" aria-label="Permalink to &quot;Q: Vue2 响应式原理&quot;">​</a></h2><p><strong>A:</strong></p><p>Vue2 基于 <code>Object.defineProperty</code> 劫持对象属性的 <code>get/set</code>，通过依赖收集和派发更新驱动渲染。</p><ol><li><code>getter</code> 触发依赖收集（记录当前 watcher）。</li><li><code>setter</code> 触发通知更新（让 watcher 重新执行）。</li><li>组件更新时会重新执行渲染函数，经过 diff 后只更新必要 DOM。</li></ol><blockquote><p>⚠️ <strong>注意</strong>：Vue2 对对象新增属性和数组下标直接赋值的监听能力有限。</p></blockquote><hr><h2 id="q-动态属性响应式怎么解决" tabindex="-1">Q: 动态属性响应式怎么解决？ <a class="header-anchor" href="#q-动态属性响应式怎么解决" aria-label="Permalink to &quot;Q: 动态属性响应式怎么解决？&quot;">​</a></h2><p><strong>A:</strong></p><p>Vue2 在初始化阶段才会把属性转成响应式，新加属性默认不会被劫持。</p><p>解决方式：</p><ol><li>使用 <code>this.$set(target, key, value)</code>。</li><li>用新对象替换旧对象：<code>this.obj = { ...this.obj, newKey: value }</code>。</li></ol><hr><h2 id="q-nexttick-作用" tabindex="-1">Q: nextTick 作用 <a class="header-anchor" href="#q-nexttick-作用" aria-label="Permalink to &quot;Q: nextTick 作用&quot;">​</a></h2><p><strong>A:</strong></p><p>Vue 会异步批量更新 DOM。<code>nextTick</code> 用来在“本轮 DOM 更新完成后”执行逻辑。</p><p>常见场景：</p><ol><li>更新状态后立即读取最新 DOM。</li><li>列表变更后计算高度或滚动位置。</li><li>弹窗展示后自动聚焦输入框。</li></ol><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D20F39;--shiki-dark:#F38BA8;">this</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">.</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">visible </span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">=</span><span style="--shiki-light:#FE640B;--shiki-dark:#FAB387;"> true</span></span>\n<span class="line"><span style="--shiki-light:#D20F39;--shiki-dark:#F38BA8;">this</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">.</span><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">$nextTick</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">(</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">()</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> =&gt;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> {</span></span>\n<span class="line"><span style="--shiki-light:#D20F39;--shiki-dark:#F38BA8;">  this</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">.</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">$refs</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">.</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">input</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">?.</span><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">focus</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">()</span></span>\n<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">}</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">)</span></span></code></pre></div><hr><h2 id="q-虚拟-dom-与-diffdiff-和-key-有什么关系" tabindex="-1">Q: 虚拟 DOM 与 diffdiff 和 <code>key</code> 有什么关系？ <a class="header-anchor" href="#q-虚拟-dom-与-diffdiff-和-key-有什么关系" aria-label="Permalink to &quot;Q: 虚拟 DOM 与 diffdiff 和 `key` 有什么关系？&quot;">​</a></h2><p><strong>A:</strong></p><p>虚拟 DOM 是用 JavaScript 对象描述 UI 结构。更新时比较新旧虚拟 DOM，最小化真实 DOM 操作。</p><p><code>key</code> 是节点稳定标识，作用是让 diff 更准确地复用与移动节点。</p><ol><li><code>key</code> 稳定且唯一：复用正确，性能更好。</li><li>用索引做 <code>key</code>：列表插入/删除时容易错位复用。</li></ol><hr><h2 id="q-vue-从-template-到真实-dom-发生了什么" tabindex="-1">Q: Vue 从 <code>template</code> 到真实 DOM 发生了什么？ <a class="header-anchor" href="#q-vue-从-template-到真实-dom-发生了什么" aria-label="Permalink to &quot;Q: Vue 从 `template` 到真实 DOM 发生了什么？&quot;">​</a></h2><p><strong>A:</strong></p><p>核心流程：</p><ol><li><code>template</code> 解析成 AST。</li><li>AST 生成 <code>render</code> 函数。</li><li><code>render</code> 生成虚拟 DOM（VNode）。</li><li><code>patch</code> 把 VNode 挂载/更新到真实 DOM。</li></ol><hr><h2 id="q-computed-和-watch-的区别是什么" tabindex="-1">Q: <code>computed</code> 和 <code>watch</code> 的区别是什么？ <a class="header-anchor" href="#q-computed-和-watch-的区别是什么" aria-label="Permalink to &quot;Q: `computed` 和 `watch` 的区别是什么？&quot;">​</a></h2><p><strong>A:</strong></p><ol><li><code>computed</code>：用于“派生状态”，有缓存，依赖不变则复用结果。</li><li><code>watch</code>：用于“副作用”，如请求接口、写缓存、手动操作 DOM。</li><li><code>computed</code> 需要返回值；<code>watch</code> 以回调处理变化。</li></ol><hr><h2 id="生命周期与组件篇" tabindex="-1">生命周期与组件篇 <a class="header-anchor" href="#生命周期与组件篇" aria-label="Permalink to &quot;生命周期与组件篇&quot;">​</a></h2><h2 id="q-vue2-生命周期如何理解" tabindex="-1">Q: Vue2 生命周期如何理解？ <a class="header-anchor" href="#q-vue2-生命周期如何理解" aria-label="Permalink to &quot;Q: Vue2 生命周期如何理解？&quot;">​</a></h2><p><strong>A:</strong></p><p>可以理解为：创建 -&gt; 挂载 -&gt; 更新 -&gt; 销毁。</p><ol><li>创建：<code>beforeCreate</code>、<code>created</code>。</li><li>挂载：<code>beforeMount</code>、<code>mounted</code>。</li><li>更新：<code>beforeUpdate</code>、<code>updated</code>。</li><li>销毁：<code>beforeDestroy</code>、<code>destroyed</code>。</li><li>缓存组件：<code>activated</code>、<code>deactivated</code>。</li></ol><p>父子渲染顺序（常见）：</p><p>父 <code>beforeCreate</code> -&gt; 父 <code>created</code> -&gt; 父 <code>beforeMount</code> -&gt; 子 <code>beforeCreate</code> -&gt; 子 <code>created</code> -&gt; 子 <code>beforeMount</code> -&gt; 子 <code>mounted</code> -&gt; 父 <code>mounted</code></p><hr><h2 id="q-data-函数式" tabindex="-1">Q: data 函数式 <a class="header-anchor" href="#q-data-函数式" aria-label="Permalink to &quot;Q: data 函数式&quot;">​</a></h2><p><strong>A:</strong></p><p>为了保证每个组件实例拥有独立数据副本，避免多个实例共享同一对象导致相互污染。</p><hr><h2 id="q-keep-alive-缓存有哪些常用配置" tabindex="-1">Q: keep-alive 缓存有哪些常用配置？ <a class="header-anchor" href="#q-keep-alive-缓存有哪些常用配置" aria-label="Permalink to &quot;Q: keep-alive 缓存有哪些常用配置？&quot;">​</a></h2><p><strong>A:</strong></p><p><code>keep-alive</code> 是内置抽象组件，用于缓存动态组件实例，避免重复销毁和重建。</p><p>常用配置：</p><ol><li><code>include</code>：仅缓存匹配组件。</li><li><code>exclude</code>：排除匹配组件。</li><li><code>max</code>：最大缓存数量（LRU 策略）。</li></ol><hr><h2 id="q-slot-插槽用法适用场景是什么" tabindex="-1">Q: slot 插槽用法适用场景是什么？ <a class="header-anchor" href="#q-slot-插槽用法适用场景是什么" aria-label="Permalink to &quot;Q: slot 插槽用法适用场景是什么？&quot;">​</a></h2><p><strong>A:</strong></p><p><code>slot</code> 是父组件向子组件分发内容的机制。</p><ol><li>默认插槽。</li><li>具名插槽。</li><li>作用域插槽（子传父数据）。</li></ol><p>适用场景：弹窗、表格、列表、表单等高复用且布局可定制的组件。</p><hr><h2 id="q-mixin-的作用和问题有哪些" tabindex="-1">Q: <code>mixin</code> 的作用和问题有哪些？ <a class="header-anchor" href="#q-mixin-的作用和问题有哪些" aria-label="Permalink to &quot;Q: `mixin` 的作用和问题有哪些？&quot;">​</a></h2><p><strong>A:</strong></p><p><code>mixin</code> 用于复用组件选项（data/methods/lifecycle）。</p><p>优点：复用快、改造旧项目成本低。<br> 缺点：命名冲突、来源不透明、维护难度高。</p><p>现代项目更推荐 Composition API 的组合函数（<code>useXxx</code>）来替代大量 mixin。</p><hr><h2 id="q-vue-组件通信方式有哪些" tabindex="-1">Q: Vue 组件通信方式有哪些？ <a class="header-anchor" href="#q-vue-组件通信方式有哪些" aria-label="Permalink to &quot;Q: Vue 组件通信方式有哪些？&quot;">​</a></h2><p><strong>A:</strong></p><ol><li>父子：<code>props</code> / <code>emit</code>。</li><li>跨层：<code>provide</code> / <code>inject</code>。</li><li>全局共享：Vuex/Pinia。</li><li>少量松耦合事件：事件总线（谨慎使用，注意可维护性）。</li></ol><hr><h2 id="q-组件-vs-插件" tabindex="-1">Q: 组件 vs 插件 <a class="header-anchor" href="#q-组件-vs-插件" aria-label="Permalink to &quot;Q: 组件 vs 插件&quot;">​</a></h2><p><strong>A:</strong></p><ol><li>组件：封装 UI 与交互逻辑，面向页面复用。</li><li>插件：扩展 Vue 全局能力，如全局方法、指令、路由、状态管理。</li></ol><p>典型插件形态是 <code>install(app)</code>，通过 <code>app.use()</code> 安装。</p><hr><h2 id="工程实战篇" tabindex="-1">工程实战篇 <a class="header-anchor" href="#工程实战篇" aria-label="Permalink to &quot;工程实战篇&quot;">​</a></h2><h2 id="q-自定义指令适合解决什么问题" tabindex="-1">Q: 自定义指令适合解决什么问题？ <a class="header-anchor" href="#q-自定义指令适合解决什么问题" aria-label="Permalink to &quot;Q: 自定义指令适合解决什么问题？&quot;">​</a></h2><p><strong>A:</strong></p><p>适合封装“底层 DOM 行为”而不是业务状态。</p><p>常见场景：自动聚焦、懒加载、权限控制、拖拽、点击外部关闭等。</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">app</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">.</span><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">directive</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">(</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;focus&#39;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">,</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> {</span></span>\n<span class="line"><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">  mounted</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">(</span><span style="--shiki-light:#E64553;--shiki-light-font-style:italic;--shiki-dark:#EBA0AC;--shiki-dark-font-style:italic;">el</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">)</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> {</span></span>\n<span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">    el</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">.</span><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">focus</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">()</span></span>\n<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">  }</span></span>\n<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">}</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">)</span></span></code></pre></div><hr><h2 id="q-vue2-过滤器-filter-了解吗" tabindex="-1">Q: Vue2 过滤器（filter）了解吗？ <a class="header-anchor" href="#q-vue2-过滤器-filter-了解吗" aria-label="Permalink to &quot;Q: Vue2 过滤器（filter）了解吗？&quot;">​</a></h2><p><strong>A:</strong></p><p>Vue2 中可用于展示层轻量格式化，但 Vue3 已移除过滤器语法。建议改用：</p><ol><li>计算属性。</li><li>方法。</li><li>可复用的格式化函数。</li></ol><hr><h2 id="q-axios-封装通常封装哪些内容" tabindex="-1">Q: axios 封装通常封装哪些内容？ <a class="header-anchor" href="#q-axios-封装通常封装哪些内容" aria-label="Permalink to &quot;Q: axios 封装通常封装哪些内容？&quot;">​</a></h2><p><strong>A:</strong></p><p>封装 axios 的目标是统一请求规范和异常处理。</p><p>常见封装点：</p><ol><li>基础配置：<code>baseURL</code>、超时、通用头。</li><li>请求拦截：鉴权 token、幂等标识。</li><li>响应拦截：统一业务码判断、错误提示、重试策略。</li><li>能力增强：取消重复请求、上传下载、按模块拆分 API。</li></ol><hr><h2 id="q-权限管理方案按钮级权限怎么做" tabindex="-1">Q: 权限管理方案按钮级权限怎么做？ <a class="header-anchor" href="#q-权限管理方案按钮级权限怎么做" aria-label="Permalink to &quot;Q: 权限管理方案按钮级权限怎么做？&quot;">​</a></h2><p><strong>A:</strong></p><ol><li>路由权限：基于角色/菜单动态生成可访问路由。</li><li>页面权限：无权限时重定向或展示 403。</li><li>按钮级权限： <ol><li>指令方案：<code>v-permission=&quot;&#39;user:create&#39;&quot;</code>。</li><li>组合函数方案：<code>hasPermission(&#39;user:create&#39;)</code>。</li></ol></li><li>权限源应由后端返回并做本地缓存，前端只负责展示与拦截。</li></ol><hr><h2 id="q-vue-项目跨域常见解决方案有哪些" tabindex="-1">Q: Vue 项目跨域常见解决方案有哪些？ <a class="header-anchor" href="#q-vue-项目跨域常见解决方案有哪些" aria-label="Permalink to &quot;Q: Vue 项目跨域常见解决方案有哪些？&quot;">​</a></h2><p><strong>A:</strong></p><ol><li>开发环境代理（Vite/webpack devServer proxy）。</li><li>后端开启 CORS。</li><li>Nginx 反向代理（生产常用）。</li><li>JSONP（仅限 GET，现代场景较少）。</li></ol><hr><h2 id="q-vue-项目部署后刷新-404-的常见原因是什么" tabindex="-1">Q: Vue 项目部署后刷新 404 的常见原因是什么？ <a class="header-anchor" href="#q-vue-项目部署后刷新-404-的常见原因是什么" aria-label="Permalink to &quot;Q: Vue 项目部署后刷新 404 的常见原因是什么？&quot;">​</a></h2><p><strong>A:</strong></p><p>常见于 <code>history</code> 路由模式：服务端找不到真实文件路径。</p><p>解决方案：</p><ol><li>服务端将未知路径回退到 <code>index.html</code>。</li><li>静态资源 <code>base/publicPath</code> 配置与部署路径一致。</li><li>检查 Nginx 或 CDN 的路由重写规则。</li></ol><hr><h2 id="q-vue-项目如何做错误处理与监控" tabindex="-1">Q: Vue 项目如何做错误处理与监控？ <a class="header-anchor" href="#q-vue-项目如何做错误处理与监控" aria-label="Permalink to &quot;Q: Vue 项目如何做错误处理与监控？&quot;">​</a></h2><p><strong>A:</strong></p><ol><li>运行时：<code>app.config.errorHandler</code> 统一捕获组件错误。</li><li>Promise：全局监听未处理拒绝。</li><li>网络层：请求拦截器统一处理状态码与重试。</li><li>监控平台：接入 Sentry/自建日志平台，记录错误上下文与用户行为。</li></ol><hr>',138)])])}const u=e(s,[["render",t]]);export{k as __pageData,u as default};
